//! Phyle Holographic Reconstruction — 27-direction emanation sieve with
//! temporal depth accumulation and noise-color-aware shell refinement.
//!
//! Combines three systems into one holographic pipeline:
//!
//! 1. **Sovereign Sieve** (holographic_reconstruction.rs): multi-view intersection
//!    filtering with heat maps and topological validation
//! 2. **Phyle Temporal Depth** (phyle_temporal_depth.rs): noise-resolved depth via
//!    triton windows (past/present/future) and standing wave extraction
//! 3. **27-Direction Emanation** (from PhyleLightEmission.lean): the Phyle cell's
//!    27 discrete directions provide the camera basis for holographic capture
//!
//! The key insight: instead of arbitrary camera positions, the holographic sieve
//! uses the Phyle's 27 emanation directions as a structured camera rig. Three
//! consecutive directions form one triton window. Shell depth increases from
//! 1 (3 views) to 27 (81 views), with noise color governing the stopping criterion.
//!
//! Resolution guarantee: PhyleContinuousManifoldClosure.lean proves that
//! resolution-indexed covers give stable Phyle encodings at every positive
//! resolution. There is no mathematical limit — only engineering constraints.

use std::collections::HashMap;

use crate::holographic_reconstruction::{
    HolographicSpace, ProjectionView, VirtualShutter, VoxelCoord, VoxelData,
};
use crate::leech_visual_sieve::{characterize_leech_visual_image, LeechVisualSieveConfig};
use crate::phyle_temporal_depth::{
    NoiseColor, PhyleTemporalCell, TritonPhase, CLOCK_PERIOD, PERFECT_FIFTH_STRIDE,
    PHYLE_DIRECTIONS,
};

// ─── 27-Direction Emanation Basis ────────────────────────────────────────────

pub fn emanation_direction(index: usize) -> (f32, f32, f32) {
    // 27 temporal slots from the 3x3x3 grid centered at origin. The center
    // slot cannot be projected as (0,0,0), so it maps to a stable unit
    // diagonal while preserving the 27-slot Phyle schedule.
    let i = index % PHYLE_DIRECTIONS;
    let ix = (i % 3) as f32 - 1.0;
    let iy = ((i / 3) % 3) as f32 - 1.0;
    let iz = (i / 9) as f32 - 1.0;
    if ix == 0.0 && iy == 0.0 && iz == 0.0 {
        let inv = 1.0_f32 / 3.0_f32.sqrt();
        return (inv, inv, inv);
    }
    let len = (ix * ix + iy * iy + iz * iz).sqrt().max(0.001);
    (ix / len, iy / len, iz / len)
}

pub fn emanation_angle(index: usize) -> f32 {
    let (x, _, z) = emanation_direction(index);
    z.atan2(x)
}

// ─── Phyle Holographic Config ────────────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct PhyleHolographicConfig {
    pub voxel_resolution: u32,
    pub shell_depth: u8,
    pub heat_threshold: f32,
    pub standing_wave_threshold: f32,
    pub deblur_threshold: f32,
    /// Enable sampled 24-D Leech visual diagnostics on RGB emanation sets.
    /// Diagnostic-only: does not change view projection or voxel geometry.
    pub enable_leech_visual_sieve: bool,
    /// Pixel stride for the Leech visual report.
    pub leech_visual_stride: usize,
    /// Config for the 24-D Leech visual descriptor.
    pub leech_visual_sieve: LeechVisualSieveConfig,
}

impl Default for PhyleHolographicConfig {
    fn default() -> Self {
        Self {
            voxel_resolution: 64,
            shell_depth: 1,
            heat_threshold: 0.01,
            standing_wave_threshold: 0.001,
            deblur_threshold: 0.01,
            enable_leech_visual_sieve: false,
            leech_visual_stride: 32,
            leech_visual_sieve: LeechVisualSieveConfig::default(),
        }
    }
}

// ─── Per-voxel temporal accumulation ─────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct HolographicVoxel {
    pub coord: VoxelCoord,
    pub heat: f32,
    pub temporal_cell: PhyleTemporalCell,
    pub noise_color: NoiseColor,
    pub shell_resolved: u8,
    pub confirmed_geometry: bool,
    pub view_count: u32,
    pub emanation_directions_seen: Vec<usize>,
}

impl HolographicVoxel {
    pub fn new(coord: VoxelCoord) -> Self {
        Self {
            coord,
            heat: 0.0,
            temporal_cell: PhyleTemporalCell::new(),
            noise_color: NoiseColor::White,
            shell_resolved: 0,
            confirmed_geometry: false,
            view_count: 0,
            emanation_directions_seen: Vec::new(),
        }
    }
}

// ─── Phyle Holographic Sieve ─────────────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct PhyleHolographicResult {
    pub total_voxels: u32,
    pub confirmed_geometry_voxels: u32,
    pub standing_wave_voxels: u32,
    pub noise_voxels: u32,
    pub shell: u8,
    pub triton_windows_completed: u32,
    pub mean_heat: f32,
    pub coverage_ratio: f32,
    pub leech_visual: Option<PhyleLeechVisualReport>,
}

#[derive(Clone, Debug, PartialEq)]
pub struct PhyleLeechVisualReport {
    pub source: String,
    pub step: f32,
    pub stride: usize,
    pub sampled_pixels: u32,
    pub origin_keys: u32,
    pub shell_keys: u32,
    pub unique_keys: u32,
    pub mean_energy_sq: f32,
    pub mean_shell_margin: f32,
}

pub struct PhyleHolographicSieve {
    pub config: PhyleHolographicConfig,
    pub space: HolographicSpace,
    pub voxels: HashMap<VoxelCoord, HolographicVoxel>,
    pub triton_windows_completed: u32,
    pub current_shell: u8,
    phase_cursor: usize,
    past_views: Vec<ProjectionView>,
    present_views: Vec<ProjectionView>,
    future_views: Vec<ProjectionView>,
}

impl PhyleHolographicSieve {
    pub fn new(config: PhyleHolographicConfig) -> Self {
        let res = config.voxel_resolution as i32;
        Self {
            space: HolographicSpace::new(res, res, res),
            voxels: HashMap::new(),
            triton_windows_completed: 0,
            current_shell: 0,
            phase_cursor: 0,
            past_views: Vec::new(),
            present_views: Vec::new(),
            future_views: Vec::new(),
            config,
        }
    }

    pub fn rotation_direction(&self) -> usize {
        (self.triton_windows_completed as usize * PERFECT_FIFTH_STRIDE) % PHYLE_DIRECTIONS
    }

    /// Ingest a single 2D view from a specific emanation direction.
    /// Views are grouped into triton windows (past/present/future) automatically.
    pub fn ingest_view(&mut self, view: ProjectionView) -> Option<PhyleHolographicResult> {
        let phase = TritonPhase::from_index(self.phase_cursor);
        match phase {
            TritonPhase::Past => self.past_views.push(view),
            TritonPhase::Present => self.present_views.push(view),
            TritonPhase::Future => self.future_views.push(view),
        }
        self.phase_cursor += 1;

        if self.phase_cursor >= CLOCK_PERIOD {
            Some(self.complete_triton_window())
        } else {
            None
        }
    }

    /// Generate views from an RGB image by simulating 27-direction emanation.
    /// Each direction produces a depth projection of the image.
    pub fn ingest_emanation_set(
        &mut self,
        rgb: &[f32],
        width: u32,
        height: u32,
    ) -> Vec<PhyleHolographicResult> {
        let mut results = Vec::new();
        let leech_visual = if self.config.enable_leech_visual_sieve {
            Some(compute_phyle_leech_visual_report(
                rgb,
                width,
                height,
                self.config.leech_visual_stride,
                &self.config.leech_visual_sieve,
            ))
        } else {
            None
        };
        let directions_per_shell = match self.config.shell_depth {
            0 => 3,
            1 => 9,
            2 => 27,
            _ => 27,
        };

        for dir_idx in 0..directions_per_shell {
            let angle = emanation_angle(dir_idx);
            let frame_data = project_rgb_to_grayscale_view(rgb, width, height, angle);

            let view = ProjectionView {
                view_id: format!("emanation-{}", dir_idx),
                angle_rad: angle,
                frame_data,
                width: width as usize,
                height: height as usize,
            };

            if let Some(mut result) = self.ingest_view(view) {
                result.leech_visual = leech_visual.clone();
                results.push(result);
            }
        }
        results
    }

    fn complete_triton_window(&mut self) -> PhyleHolographicResult {
        let res = self.config.voxel_resolution as i32;
        let dims = self.space.dims;
        let all_views: Vec<&ProjectionView> = self
            .past_views
            .iter()
            .chain(self.present_views.iter())
            .chain(self.future_views.iter())
            .collect();

        // Run the sovereign sieve with temporal accumulation
        for z in 0..res {
            for y in 0..res {
                for x in 0..res {
                    let coord = VoxelCoord { x, y, z };
                    let mut heat = 1.0f32;
                    let mut verified = 0u32;

                    // Compute heat from all views in this triton window
                    for view in &all_views {
                        let (u, v) = VirtualShutter::project(coord, view, dims);
                        if v * view.width + u < view.frame_data.len() {
                            let pixel = view.frame_data[v * view.width + u] as f32 / 255.0;
                            heat *= pixel;
                            if pixel > 0.5 {
                                verified += 1;
                            }
                        }
                    }

                    if heat > self.config.heat_threshold {
                        // Compute phase heats before mutable borrow
                        let past_heat = compute_phase_heat(&coord, &self.past_views, dims);
                        let present_heat = compute_phase_heat(&coord, &self.present_views, dims);
                        let future_heat = compute_phase_heat(&coord, &self.future_views, dims);
                        let sw_thresh = self.config.standing_wave_threshold;
                        let db_thresh = self.config.deblur_threshold;
                        let rot_dir = self.rotation_direction();
                        let shell = self.current_shell;
                        let is_path = verified == all_views.len() as u32;

                        let voxel = self
                            .voxels
                            .entry(coord)
                            .or_insert_with(|| HolographicVoxel::new(coord));

                        voxel
                            .temporal_cell
                            .ingest(TritonPhase::Past, past_heat, heat, heat);
                        voxel
                            .temporal_cell
                            .ingest(TritonPhase::Present, present_heat, heat, heat);
                        voxel
                            .temporal_cell
                            .ingest(TritonPhase::Future, future_heat, heat, heat);
                        voxel.temporal_cell.compute_diffs();
                        voxel.temporal_cell.classify_noise(sw_thresh, db_thresh);

                        voxel.heat = heat;
                        voxel.noise_color = voxel.temporal_cell.noise_color;
                        voxel.view_count = verified;
                        voxel.emanation_directions_seen.push(rot_dir);

                        if voxel.temporal_cell.try_resolve(shell) {
                            voxel.confirmed_geometry = true;
                            voxel.shell_resolved = shell;
                        }

                        self.space.voxels.insert(
                            coord,
                            VoxelData {
                                heat,
                                is_path,
                                metadata: HashMap::new(),
                            },
                        );
                    }
                }
            }
        }

        // Compute result
        let total = self.voxels.len() as u32;
        let confirmed = self
            .voxels
            .values()
            .filter(|v| v.confirmed_geometry)
            .count() as u32;
        let standing = self
            .voxels
            .values()
            .filter(|v| v.noise_color == NoiseColor::StandingWave)
            .count() as u32;
        let noise = self
            .voxels
            .values()
            .filter(|v| v.noise_color == NoiseColor::White)
            .count() as u32;
        let mean_heat = if total > 0 {
            self.voxels.values().map(|v| v.heat).sum::<f32>() / total as f32
        } else {
            0.0
        };
        let max_voxels = (res * res * res) as f32;

        self.triton_windows_completed += 1;
        self.phase_cursor = 0;
        self.past_views.clear();
        self.present_views.clear();
        self.future_views.clear();

        // Shell promotion
        let windows_for_next = CLOCK_PERIOD.pow(self.current_shell as u32 + 1) as u32;
        if self.triton_windows_completed >= windows_for_next && self.current_shell < 3 {
            self.current_shell += 1;
        }

        PhyleHolographicResult {
            total_voxels: total,
            confirmed_geometry_voxels: confirmed,
            standing_wave_voxels: standing,
            noise_voxels: noise,
            shell: self.current_shell,
            triton_windows_completed: self.triton_windows_completed,
            mean_heat,
            coverage_ratio: total as f32 / max_voxels,
            leech_visual: None,
        }
    }

    /// Export confirmed geometry as PLY point cloud.
    pub fn export_ply(&self) -> Vec<u8> {
        let confirmed: Vec<&HolographicVoxel> = self
            .voxels
            .values()
            .filter(|v| v.confirmed_geometry)
            .collect();

        let mut ply = format!(
            "ply\nformat ascii 1.0\nelement vertex {}\n\
             property float x\nproperty float y\nproperty float z\n\
             property uchar red\nproperty uchar green\nproperty uchar blue\n\
             end_header\n",
            confirmed.len()
        );

        let res = self.config.voxel_resolution as f32;
        for v in &confirmed {
            let nx = v.coord.x as f32 / res * 2.0 - 1.0;
            let ny = v.coord.y as f32 / res * 2.0 - 1.0;
            let nz = v.coord.z as f32 / res * 2.0 - 1.0;

            // Color by noise color: standing=amber, pink=green, brown=blue
            let (r, g, b) = match v.noise_color {
                NoiseColor::StandingWave => (251, 191, 36), // amber
                NoiseColor::Pink => (74, 222, 128),         // green
                NoiseColor::Brown => (96, 165, 250),        // blue
                NoiseColor::White => (148, 163, 184),       // gray
            };

            ply.push_str(&format!(
                "{:.4} {:.4} {:.4} {} {} {}\n",
                nx, ny, nz, r, g, b
            ));
        }

        ply.into_bytes()
    }

    /// Export parallax layers (foreground/midground/background) as separate PLY clouds.
    pub fn export_parallax_layers(&self) -> (Vec<u8>, Vec<u8>, Vec<u8>) {
        let res = self.config.voxel_resolution as f32;
        let fg_threshold = res * 0.33;
        let mg_threshold = res * 0.66;

        let mut fg_ply = String::new();
        let mut mg_ply = String::new();
        let mut bg_ply = String::new();
        let mut fg_count = 0u32;
        let mut mg_count = 0u32;
        let mut bg_count = 0u32;

        for v in self.voxels.values().filter(|v| v.confirmed_geometry) {
            let depth = v.coord.z as f32;
            let nx = v.coord.x as f32 / res * 2.0 - 1.0;
            let ny = v.coord.y as f32 / res * 2.0 - 1.0;
            let nz = v.coord.z as f32 / res * 2.0 - 1.0;
            let heat_byte = (v.heat * 255.0).min(255.0) as u8;

            let line = format!(
                "{:.4} {:.4} {:.4} {} {} {}\n",
                nx, ny, nz, heat_byte, heat_byte, heat_byte
            );

            if depth < fg_threshold {
                fg_ply.push_str(&line);
                fg_count += 1;
            } else if depth < mg_threshold {
                mg_ply.push_str(&line);
                mg_count += 1;
            } else {
                bg_ply.push_str(&line);
                bg_count += 1;
            }
        }

        let header = |count: u32| {
            format!(
                "ply\nformat ascii 1.0\nelement vertex {}\n\
             property float x\nproperty float y\nproperty float z\n\
             property uchar red\nproperty uchar green\nproperty uchar blue\n\
             end_header\n",
                count
            )
        };

        (
            format!("{}{}", header(fg_count), fg_ply).into_bytes(),
            format!("{}{}", header(mg_count), mg_ply).into_bytes(),
            format!("{}{}", header(bg_count), bg_ply).into_bytes(),
        )
    }
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

fn compute_phyle_leech_visual_report(
    rgb: &[f32],
    width: u32,
    height: u32,
    stride: usize,
    cfg: &LeechVisualSieveConfig,
) -> PhyleLeechVisualReport {
    let stride = stride.max(1);
    let report = characterize_leech_visual_image(rgb, width as usize, height as usize, stride, cfg);
    PhyleLeechVisualReport {
        source: "rgb-emanation-set".to_string(),
        step: cfg.step,
        stride,
        sampled_pixels: report.n.min(u32::MAX as usize) as u32,
        origin_keys: report.origin_keys.min(u32::MAX as usize) as u32,
        shell_keys: report.shell_keys.min(u32::MAX as usize) as u32,
        unique_keys: report.unique_keys.min(u32::MAX as usize) as u32,
        mean_energy_sq: report.mean_energy_sq,
        mean_shell_margin: report.mean_shell_margin,
    }
}

fn compute_phase_heat(coord: &VoxelCoord, views: &[ProjectionView], dims: VoxelCoord) -> f32 {
    if views.is_empty() {
        return 0.0;
    }
    let mut heat = 1.0f32;
    for view in views {
        let (u, v) = VirtualShutter::project(*coord, view, dims);
        if v * view.width + u < view.frame_data.len() {
            heat *= view.frame_data[v * view.width + u] as f32 / 255.0;
        }
    }
    heat
}

fn project_rgb_to_grayscale_view(rgb: &[f32], width: u32, height: u32, angle: f32) -> Vec<u8> {
    let pix = (width * height) as usize;
    let mut frame = vec![0u8; pix];
    let cos_a = angle.cos();
    let _sin_a = angle.sin();
    let cx = width as f32 / 2.0;

    for y in 0..height as usize {
        for x in 0..width as usize {
            // Simulate depth-rotated view: shift columns by angle-weighted offset
            let tx = x as f32 - cx;
            let rx = tx * cos_a;
            let sx = (rx + cx).round().clamp(0.0, (width - 1) as f32) as usize;

            let src = y * width as usize + sx;
            if src * 3 + 2 < rgb.len() {
                // Rec.709 luma
                let luma =
                    rgb[src * 3] * 0.2126 + rgb[src * 3 + 1] * 0.7152 + rgb[src * 3 + 2] * 0.0722;
                frame[y * width as usize + x] = (luma * 255.0).clamp(0.0, 255.0) as u8;
            }
        }
    }
    frame
}

// ─── Tests ───────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    fn synthetic_rgb(width: u32, height: u32) -> Vec<f32> {
        let mut rgb = vec![0.0_f32; (width * height * 3) as usize];
        for y in 0..height as usize {
            for x in 0..width as usize {
                let base = (y * width as usize + x) * 3;
                let fx = x as f32;
                let fy = y as f32;
                let v = (0.5
                    + 0.22 * (fx * 0.17).sin()
                    + 0.18 * (fy * 0.23).cos()
                    + 0.08 * ((fx + fy) * 0.13).sin())
                .clamp(0.0, 1.0);
                rgb[base] = v;
                rgb[base + 1] = (0.85 * v + 0.08).clamp(0.0, 1.0);
                rgb[base + 2] = (0.7 * v + 0.18).clamp(0.0, 1.0);
            }
        }
        rgb
    }

    #[test]
    fn test_emanation_directions_cover_sphere() {
        for i in 0..PHYLE_DIRECTIONS {
            let (x, y, z) = emanation_direction(i);
            let len = (x * x + y * y + z * z).sqrt();
            assert!(
                (len - 1.0).abs() < 0.01,
                "direction {} not unit: {}",
                i,
                len
            );
        }
    }

    #[test]
    fn test_holographic_sieve_basic() {
        let config = PhyleHolographicConfig {
            voxel_resolution: 8,
            shell_depth: 0,
            ..Default::default()
        };
        let mut sieve = PhyleHolographicSieve::new(config);

        // Create 3 simple views (one triton window)
        for i in 0..3 {
            let angle = emanation_angle(i);
            let view = ProjectionView {
                view_id: format!("test-{}", i),
                angle_rad: angle,
                frame_data: vec![200u8; 64], // 8x8 bright
                width: 8,
                height: 8,
            };
            let result = sieve.ingest_view(view);
            if i == 2 {
                assert!(result.is_some());
                let r = result.unwrap();
                assert!(r.total_voxels > 0);
                assert_eq!(r.triton_windows_completed, 1);
                assert!(r.leech_visual.is_none());
            }
        }
    }

    #[test]
    fn test_emanation_set_attaches_leech_visual_report_when_enabled() {
        let config = PhyleHolographicConfig {
            voxel_resolution: 4,
            shell_depth: 0,
            enable_leech_visual_sieve: true,
            leech_visual_stride: 8,
            ..Default::default()
        };
        let mut sieve = PhyleHolographicSieve::new(config.clone());
        let rgb = synthetic_rgb(16, 16);
        let results = sieve.ingest_emanation_set(&rgb, 16, 16);
        assert_eq!(results.len(), 1);
        let report = results[0].leech_visual.as_ref().expect("Leech report");
        assert_eq!(report.source, "rgb-emanation-set");
        assert_eq!(report.step, config.leech_visual_sieve.step);
        assert_eq!(report.stride, 8);
        assert!(report.sampled_pixels > 0);
        assert_eq!(
            report.origin_keys + report.shell_keys,
            report.sampled_pixels
        );
        assert!(report.unique_keys > 0);
        assert!(report.mean_energy_sq.is_finite());
        assert!(report.mean_shell_margin.is_finite());
    }

    #[test]
    fn test_ply_export() {
        let config = PhyleHolographicConfig {
            voxel_resolution: 4,
            shell_depth: 0,
            ..Default::default()
        };
        let mut sieve = PhyleHolographicSieve::new(config);

        for i in 0..3 {
            let view = ProjectionView {
                view_id: format!("v{}", i),
                angle_rad: emanation_angle(i),
                frame_data: vec![255u8; 16],
                width: 4,
                height: 4,
            };
            sieve.ingest_view(view);
        }

        let ply = sieve.export_ply();
        let ply_str = String::from_utf8(ply).unwrap();
        assert!(ply_str.starts_with("ply\n"));
        assert!(ply_str.contains("end_header"));
    }
}
